export enum ConversionStatus {
  IDLE = 'IDLE',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR',
}

export interface ImageFile {
  id: string;
  file: File;
  previewUrl: string;
  status: ConversionStatus;
  convertedBlob?: Blob;
  errorMessage?: string;
  originalSize: number;
  convertedSize?: number;
  width?: number;
  height?: number;
}

export interface LayerImage {
  id: string;
  file: File;
  previewUrl: string;
  x: number;
  y: number;
  scale: number;
  width: number;
  height: number;
  originalWidth: number;
  originalHeight: number;
}

export interface ZipTask {
  id: string;
  folderName: string;
  files: File[];
  status: ConversionStatus;
  zipBlob?: Blob;
  totalSize: number;
  zipSize?: number;
  progress?: number; // 0 to 100
}

export interface ConversionConfig {
  quality: number; // 0.1 to 1.0
  fillColor: string; // Background color for transparency replacement
  scale: number; // 0.01 to 1.0 (Resize percentage)
}

export interface CropperConfig {
  outputSize: number; // e.g., 1024
  quality: number;
  fillColor: string;
}

import { useState, useCallback } from 'react';
import { LayerImage, CropperConfig } from '../types';
import { generateId, getZip } from '../utils/common';
import { getImageDimensions } from '../utils/imageHelper';

export const useLayerCropper = () => {
  const [layers, setLayers] = useState<LayerImage[]>([]);
  const [activeLayerId, setActiveLayerId] = useState<string | null>(null);
  const [config, setConfig] = useState<CropperConfig>({
    outputSize: 1024,
    quality: 0.9,
    fillColor: '#000000',
  });
  const [isExporting, setIsExporting] = useState(false);

  const activeLayer = layers.find(l => l.id === activeLayerId) || null;

  const handleFilesAdded = useCallback(async (files: File[]) => {
    const newLayersPromises = files.map(async (file) => {
      const { width, height } = await getImageDimensions(file);

      // Default: Scale to cover a square
      const minSide = Math.min(width, height);
      const initialScale = 1.0; 

      return {
        id: generateId(),
        file,
        previewUrl: URL.createObjectURL(file),
        x: 0,
        y: 0,
        scale: initialScale,
        width: width,
        height: height,
        originalWidth: width,
        originalHeight: height,
      } as LayerImage;
    });

    const newLayers = await Promise.all(newLayersPromises);
    setLayers(prev => [...prev, ...newLayers]);
    if (!activeLayerId && newLayers.length > 0) {
      setActiveLayerId(newLayers[0].id);
    }
  }, [activeLayerId]);

  const updateActiveLayer = useCallback((updates: Partial<LayerImage>) => {
    if (!activeLayerId) return;
    setLayers(prev => prev.map(l => l.id === activeLayerId ? { ...l, ...updates } : l));
  }, [activeLayerId]);

  const removeLayer = useCallback((id: string) => {
    setLayers(prev => {
      const filtered = prev.filter(l => l.id !== id);
      if (activeLayerId === id) {
        setActiveLayerId(filtered.length > 0 ? filtered[0].id : null);
      }
      return filtered;
    });
  }, [activeLayerId]);

  const exportAll = async () => {
    if (layers.length === 0) return;
    setIsExporting(true);

    try {
      const zip = getZip();
      const canvas = document.createElement('canvas');
      canvas.width = config.outputSize;
      canvas.height = config.outputSize;
      const ctx = canvas.getContext('2d')!;

      for (const layer of layers) {
        // Draw each layer
        ctx.fillStyle = config.fillColor;
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        const img = await new Promise<HTMLImageElement>((resolve) => {
          const i = new Image();
          i.onload = () => resolve(i);
          i.src = layer.previewUrl;
        });

        // The logic: 
        // We need to translate the relative layer units to the output canvas units
        // Assuming 'scale: 1' means the image's original size
        // And (x, y) are offsets from the center of the mask

        ctx.save();
        ctx.translate(canvas.width / 2, canvas.height / 2);

        const drawWidth = layer.originalWidth * layer.scale;
        const drawHeight = layer.originalHeight * layer.scale;

        ctx.drawImage(
          img, 
          layer.x - drawWidth / 2, 
          layer.y - drawHeight / 2, 
          drawWidth, 
          drawHeight
        );
        ctx.restore();

        const blob = await new Promise<Blob | null>(resolve => canvas.toBlob(resolve, 'image/jpeg', config.quality));
        if (blob) {
          zip.file(`${layer.file.name.replace(/\.[^/.]+$/, "")}_square.jpg`, blob);
        }
      }

      const content = await zip.generateAsync({ type: "blob" });
      const url = URL.createObjectURL(content);
      const a = document.createElement("a");
      a.href = url;
      a.download = `BatchBox_Square_Layers_${new Date().toISOString().slice(0,10)}.zip`;
      a.click();
      URL.revokeObjectURL(url);
    } catch (err) {
      console.error(err);
    } finally {
      setIsExporting(false);
    }
  };

  return {
    layers,
    activeLayer,
    activeLayerId,
    setActiveLayerId,
    config,
    setConfig,
    handleFilesAdded,
    updateActiveLayer,
    removeLayer,
    exportAll,
    isExporting
  };
};

import React, { useRef, useState, useEffect } from 'react';
import { useLayerCropper } from '../../hooks/useLayerCropper';
import { Layers, Maximize, Move, Trash2, Download, RefreshCw, ZoomIn, ZoomOut, Center } from 'lucide-react';
import Dropzone from '../Dropzone';

interface LayerCropperViewProps {
  controller: ReturnType<typeof useLayerCropper>;
}

const LayerCropperView: React.FC<LayerCropperViewProps> = ({ controller }) => {
  const {
    layers,
    activeLayer,
    activeLayerId,
    setActiveLayerId,
    config,
    setConfig,
    handleFilesAdded,
    updateActiveLayer,
    removeLayer,
    exportAll,
    isExporting
  } = controller;

  const workspaceRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const [initialPos, setInitialPos] = useState({ x: 0, y: 0 });

  const onMouseDown = (e: React.MouseEvent) => {
    if (!activeLayer) return;
    setIsDragging(true);
    setDragStart({ x: e.clientX, y: e.clientY });
    setInitialPos({ x: activeLayer.x, y: activeLayer.y });
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging || !activeLayer) return;
      const dx = e.clientX - dragStart.x;
      const dy = e.clientY - dragStart.y;
      updateActiveLayer({
        x: initialPos.x + dx,
        y: initialPos.y + dy
      });
    };

    const handleMouseUp = () => setIsDragging(false);

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, activeLayer, dragStart, initialPos, updateActiveLayer]);

  const autoFit = () => {
    if (!activeLayer) return;
    // Fit means the image is contained within the square
    const scale = Math.min(1, 400 / Math.max(activeLayer.originalWidth, activeLayer.originalHeight));
    updateActiveLayer({ x: 0, y: 0, scale: scale });
  };

  const autoFill = () => {
    if (!activeLayer) return;
    // Fill means the square is completely covered by the image
    const scale = 400 / Math.min(activeLayer.originalWidth, activeLayer.originalHeight);
    updateActiveLayer({ x: 0, y: 0, scale: scale });
  };

  return (
    <main className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1 animate-in fade-in slide-in-from-bottom-2 duration-300">

      {/* Sidebar: Control & Layers */}
      <div className="lg:col-span-3 space-y-4 flex flex-col h-full">
        {/* Export Controls */}
        <div className="bg-cyber-panel/40 border border-cyber-border p-4 rounded-lg">
          <h2 className="text-xs font-bold text-cyber-primary uppercase tracking-widest mb-4 flex items-center gap-2">
            <Maximize size={14} /> Output Config
          </h2>
          <div className="space-y-4">
             <div>
               <label className="text-[10px] text-cyber-dim block mb-1">TARGET RESOLUTION</label>
               <select 
                 value={config.outputSize} 
                 onChange={(e) => setConfig({...config, outputSize: Number(e.target.value)})}
                 className="w-full bg-cyber-black border border-cyber-border text-cyber-text text-sm p-2 rounded focus:border-cyber-primary outline-none"
               >
                 <option value={512}>512 x 512</option>
                 <option value={1024}>1024 x 1024</option>
                 <option value={2048}>2048 x 2048</option>
               </select>
             </div>
             <button
               onClick={exportAll}
               disabled={isExporting || layers.length === 0}
               className="w-full py-3 bg-cyber-primary/10 border border-cyber-primary text-cyber-primary font-bold text-xs uppercase tracking-widest hover:bg-cyber-primary/20 transition-all flex items-center justify-center gap-2"
             >
               {isExporting ? <RefreshCw size={16} className="animate-spin" /> : <Download size={16} />}
               EXPORT ZIP
             </button>
          </div>
        </div>

        {/* Layer List */}
        <div className="flex-1 bg-cyber-panel/20 border border-cyber-border rounded-lg flex flex-col overflow-hidden min-h-[300px]">
          <div className="p-3 border-b border-cyber-border/50 bg-cyber-black/40 flex justify-between items-center">
            <span className="text-[10px] font-bold text-cyber-dim uppercase tracking-widest">Layers [{layers.length}]</span>
            <Layers size={14} className="text-cyber-dim" />
          </div>
          <div className="flex-1 overflow-y-auto p-2 space-y-2 custom-scrollbar">
            {layers.length === 0 && (
              <div className="text-center py-10 text-cyber-dim/30 italic text-sm">No images imported</div>
            )}
            {layers.map(layer => (
              <div 
                key={layer.id}
                onClick={() => setActiveLayerId(layer.id)}
                className={`group p-2 border transition-all cursor-pointer flex items-center gap-3 relative ${
                  activeLayerId === layer.id 
                    ? 'border-cyber-primary bg-cyber-primary/10 shadow-[0_0_10px_rgba(6,182,212,0.1)]' 
                    : 'border-cyber-border bg-cyber-black/40 hover:border-cyber-dim'
                }`}
              >
                <div className="w-10 h-10 bg-cyber-dark rounded overflow-hidden flex-shrink-0 border border-cyber-border/50">
                  <img src={layer.previewUrl} className="w-full h-full object-cover" alt="" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-[10px] text-cyber-text truncate font-mono">{layer.file.name}</p>
                  <p className="text-[8px] text-cyber-dim font-mono">{layer.originalWidth}x{layer.originalHeight}</p>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); removeLayer(layer.id); }}
                  className="opacity-0 group-hover:opacity-100 p-1 text-red-400 hover:text-red-300 transition-opacity"
                >
                  <Trash2 size={12} />
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Main Workspace */}
      <div className="lg:col-span-9 flex flex-col gap-4">
        {layers.length === 0 ? (
          <div className="flex-1 border-2 border-dashed border-cyber-border rounded-xl flex items-center justify-center p-12 bg-cyber-black/20">
            <div className="max-w-md w-full">
              <Dropzone onFilesAdded={handleFilesAdded} />
            </div>
          </div>
        ) : (
          <>
            {/* Editor Area */}
            <div className="flex-1 bg-cyber-dark/80 border border-cyber-border rounded-xl relative overflow-hidden flex items-center justify-center min-h-[500px] shadow-inner select-none">
              <div className="absolute inset-0 pointer-events-none opacity-20 bg-[radial-gradient(#334155_1px,transparent_1px)] bg-[size:20px_20px]"></div>

              {/* Toolbar */}
              <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                 <button onClick={autoFit} className="p-2 bg-cyber-black/80 border border-cyber-border text-cyber-text hover:text-cyber-primary transition-colors rounded shadow-lg" title="Fit to Square">
                   <Maximize size={18} />
                 </button>
                 <button onClick={autoFill} className="p-2 bg-cyber-black/80 border border-cyber-border text-cyber-text hover:text-cyber-accent transition-colors rounded shadow-lg" title="Fill Square">
                   <Move size={18} />
                 </button>
                 <button onClick={() => updateActiveLayer({x:0, y:0})} className="p-2 bg-cyber-black/80 border border-cyber-border text-cyber-text hover:text-emerald-400 transition-colors rounded shadow-lg" title="Center">
                   <Center size={18} />
                 </button>
              </div>

              {/* Zoom Controls */}
              <div className="absolute bottom-4 right-4 z-20 flex gap-2">
                 <button 
                   onClick={() => activeLayer && updateActiveLayer({scale: activeLayer.scale * 1.1})}
                   className="p-2 bg-cyber-black/80 border border-cyber-border text-cyber-text hover:text-cyber-primary rounded shadow-lg"
                 >
                   <ZoomIn size={18} />
                 </button>
                 <button 
                   onClick={() => activeLayer && updateActiveLayer({scale: activeLayer.scale / 1.1})}
                   className="p-2 bg-cyber-black/80 border border-cyber-border text-cyber-text hover:text-cyber-primary rounded shadow-lg"
                 >
                   <ZoomOut size={18} />
                 </button>
              </div>

              {/* Square Mask Container */}
              <div 
                className="w-[400px] h-[400px] bg-[#111] border-2 border-cyber-primary shadow-[0_0_30px_rgba(6,182,212,0.15)] relative overflow-hidden"
                onMouseDown={onMouseDown}
              >
                {/* Background Checkerboard */}
                <div className="absolute inset-0 opacity-10 bg-[linear-gradient(45deg,#888_25%,transparent_25%),linear-gradient(-45deg,#888_25%,transparent_25%),linear-gradient(45deg,transparent_75%,#888_75%),linear-gradient(-45deg,transparent_75%,#888_75%)] bg-[size:20px_20px] bg-[position:0_0,0_10px,10px_-10px,-10px_0px]"></div>

                {/* Active Layer Image */}
                {activeLayer && (
                  <div 
                    className="absolute cursor-move origin-center"
                    style={{
                      transform: `translate(calc(-50% + ${activeLayer.x}px), calc(-50% + ${activeLayer.y}px))`,
                      top: '50%',
                      left: '50%',
                      width: activeLayer.originalWidth * activeLayer.scale,
                      height: activeLayer.originalHeight * activeLayer.scale
                    }}
                  >
                    <img 
                      src={activeLayer.previewUrl} 
                      className="w-full h-full object-contain pointer-events-none" 
                      alt="" 
                    />
                    {/* Visual boundary */}
                    <div className="absolute inset-0 border border-cyber-primary/30 pointer-events-none"></div>
                  </div>
                )}

                {/* Overlay Mask (optional darkening outside if container was larger) */}
              </div>

              {/* Instruction */}
              <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-[10px] font-mono text-cyber-dim bg-cyber-black/60 px-4 py-2 rounded-full border border-cyber-border/30">
                DRAG TO POSITION • MOUSE WHEEL OR BUTTONS TO ZOOM
              </div>
            </div>

            {/* Quick Add Bottom */}
            <div className="h-20">
               <Dropzone onFilesAdded={handleFilesAdded} compact={true} />
            </div>
          </>
        )}
      </div>
    </main>
  );
};

