/**
 * Calculates a monotonic cubic spline interpolation for the given points.
 * Returns a Lookup Table (LUT) array of 256 integers (0-255).
 */
export const generateCurveLUT = (points: CurvePoint[]): number[] => {
  // 1. Sort points by X
  const sortedPoints = [...points].sort((a, b) => a.x - b.x);

  // Ensure start (0,0) and end (255,255) logical bounds if not present?
  // Usually curve tools imply extension to bounds. 
  // For simplicity, if the user doesn't define 0 or 255, we clamp or extend.
  // But strictly, we interpolate between the defined points and clamp outside.

  const xs = sortedPoints.map(p => p.x);
  const ys = sortedPoints.map(p => p.y);
  const n = sortedPoints.length;

  if (n < 2) {
    // Linear fallback or identity if only 1 point
    const lut = [];
    for (let i = 0; i < 256; i++) lut[i] = i;
    return lut;
  }

  // Monotone Cubic Spline Interpolation
  // Calculate secants and tangents
  const m = new Array(n).fill(0);
  const dxs = [];
  const dys = [];

  for (let i = 0; i < n - 1; i++) {
    const dx = xs[i + 1] - xs[i];
    const dy = ys[i + 1] - ys[i];
    dxs.push(dx);
    dys.push(dy);
  }

  const ms = [];
  for (let i = 0; i < n - 1; i++) {
    ms.push(dys[i] / dxs[i]);
  }

  // Determine tangents at data points
  const c1s = [ms[0]];
  for (let i = 0; i < n - 2; i++) {
    if (ms[i] * ms[i+1] <= 0) {
      c1s.push(0);
    } else {
      // Standard average
      c1s.push((ms[i] + ms[i+1]) / 2); 
    }
  }
  c1s.push(ms[n - 2]);

  // Generate LUT
  const lut = new Array(256).fill(0);

  // Helper to get Y for specific X
  const getY = (targetX: number) => {
    // Find segment
    let i = 0;
    if (targetX <= xs[0]) return ys[0];
    if (targetX >= xs[n - 1]) return ys[n - 1];

    for (let j = 0; j < n - 1; j++) {
      if (targetX >= xs[j] && targetX < xs[j + 1]) {
        i = j;
        break;
      }
    }

    // Hermite basis functions
    const h = xs[i + 1] - xs[i];
    const t = (targetX - xs[i]) / h;
    const t2 = t * t;
    const t3 = t2 * t;

    const p0 = ys[i];
    const p1 = ys[i + 1];
    const m0 = c1s[i];
    const m1 = c1s[i + 1];

    const h00 = 2 * t3 - 3 * t2 + 1;
    const h10 = t3 - 2 * t2 + t;
    const h01 = -2 * t3 + 3 * t2;
    const h11 = t3 - t2;

    const y = h00 * p0 + h10 * h * m0 + h01 * p1 + h11 * h * m1;
    return Math.max(0, Math.min(255, Math.round(y)));
  };

  for (let i = 0; i < 256; i++) {
    lut[i] = getY(i);
  }

  return lut;
};

import { ConversionConfig } from '../types';

/**
 * Gets the dimensions (width and height) of an image file.
 */
export const getImageDimensions = (file: File): Promise<{width: number, height: number}> => {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () => {
      resolve({ width: img.width, height: img.height });
      URL.revokeObjectURL(img.src);
    };
    img.onerror = () => {
      resolve({ width: 0, height: 0 });
    };
    img.src = URL.createObjectURL(file);
  });
};

/**
 * Converts an image file (PNG, JPG, etc.) to a JPG Blob.
 */
export const convertImageToJpg = async (
  file: File,
  config: ConversionConfig
): Promise<Blob> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();

    reader.onload = (e) => {
      const img = new Image();

      img.onload = () => {
        const scale = config.scale || 1;
        const targetWidth = Math.max(1, Math.floor(img.width * scale));
        const targetHeight = Math.max(1, Math.floor(img.height * scale));

        const canvas = document.createElement('canvas');
        canvas.width = targetWidth;
        canvas.height = targetHeight;
        const ctx = canvas.getContext('2d');

        if (!ctx) {
          reject(new Error('Canvas context could not be created'));
          return;
        }

        ctx.fillStyle = config.fillColor;
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.imageSmoothingEnabled = true;
        ctx.imageSmoothingQuality = 'high';
        ctx.drawImage(img, 0, 0, targetWidth, targetHeight);

        canvas.toBlob(
          (blob) => {
            if (blob) {
              resolve(blob);
            } else {
              reject(new Error('Canvas conversion failed'));
            }
          },
          'image/jpeg',
          config.quality
        );
      };

      img.onerror = () => reject(new Error('Failed to load image'));
      img.src = e.target?.result as string;
    };

    reader.onerror = () => reject(new Error('Failed to read file'));
    reader.readAsDataURL(file);
  });
};

/**
 * Applies a Curves Lookup Table (LUT) to an image file.
 */
export const applyCurvesToImage = async (
  file: File,
  lut: number[],
  quality: number = 0.9
): Promise<Blob> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      canvas.width = img.width;
      canvas.height = img.height;
      const ctx = canvas.getContext('2d');

      if (!ctx) {
        reject(new Error('Canvas error'));
        return;
      }

      ctx.drawImage(img, 0, 0);

      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const data = imageData.data;

      // Apply LUT to RGB channels
      for (let i = 0; i < data.length; i += 4) {
        data[i] = lut[data[i]];     // R
        data[i + 1] = lut[data[i + 1]]; // G
        data[i + 2] = lut[data[i + 2]]; // B
        // Alpha (i+3) remains unchanged
      }

      ctx.putImageData(imageData, 0, 0);

      canvas.toBlob((blob) => {
        if (blob) resolve(blob);
        else reject(new Error('Encoding failed'));
      }, 'image/jpeg', quality); // Default output to JPG
    };

    img.onerror = (err) => reject(err);
    img.src = URL.createObjectURL(file);
  });
};

export const formatBytes = (bytes: number, decimals = 2) => {
  if (bytes === 0) return '0 Bytes';
  const k = 1024;
  const dm = decimals < 0 ? 0 : decimals;
  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
};

import { useState, useCallback, useMemo, useEffect } from 'react';
import { ImageFile, ConversionStatus, CurvePoint } from '../types';
import { applyCurvesToImage, getImageDimensions } from '../utils/imageHelper';
import { generateCurveLUT } from '../utils/curveAlgorithms';
import { generateId, getZip } from '../utils/common';

const DEFAULT_POINTS: CurvePoint[] = [
  { id: 'start', x: 0, y: 0 },
  { id: 'end', x: 255, y: 255 }
];

export const useImageCurves = () => {
  const [files, setFiles] = useState<ImageFile[]>([]);
  const [points, setPoints] = useState<CurvePoint[]>(DEFAULT_POINTS);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activePreviewId, setActivePreviewId] = useState<string | null>(null);
  // Store the live preview blob URL to avoid re-rendering heavy canvas operations on every frame
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  // Computed LUT based on points
  const lut = useMemo(() => generateCurveLUT(points), [points]);

  const handleFilesAdded = useCallback(async (newFiles: File[]) => {
    const processedFilesPromises = newFiles.map(async (file) => {
      const dimensions = await getImageDimensions(file);
      return {
        id: generateId(),
        file,
        previewUrl: URL.createObjectURL(file), // Original Preview
        status: ConversionStatus.IDLE,
        originalSize: file.size,
        width: dimensions.width,
        height: dimensions.height,
      } as ImageFile;
    });

    const newImageFiles = await Promise.all(processedFilesPromises);
    setFiles(prev => {
        const updated = [...prev, ...newImageFiles];
        // Set first file as preview if none selected
        if (!activePreviewId && updated.length > 0) {
            setActivePreviewId(updated[0].id);
        }
        return updated;
    });
  }, [activePreviewId]);

  const handleRemoveFile = useCallback((id: string) => {
    setFiles(prev => {
      const target = prev.find(f => f.id === id);
      if (target) {
        URL.revokeObjectURL(target.previewUrl);
      }
      const remaining = prev.filter(f => f.id !== id);
      if (activePreviewId === id) {
          setActivePreviewId(remaining.length > 0 ? remaining[0].id : null);
      }
      return remaining;
    });
  }, [activePreviewId]);

  const addPoint = (x: number, y: number) => {
    // Don't add if too close to existing x
    if (points.some(p => Math.abs(p.x - x) < 5)) return;

    const newPoint: CurvePoint = { id: generateId(), x, y };
    setPoints(prev => [...prev, newPoint].sort((a, b) => a.x - b.x));
  };

  const updatePoint = (id: string, x: number, y: number) => {
    setPoints(prev => prev.map(p => {
        if (p.id !== id) return p;
        // Limit X movement to not cross other points? 
        // For simplicity, flexible x/y but clamped to 0-255
        return { ...p, x: Math.max(0, Math.min(255, x)), y: Math.max(0, Math.min(255, y)) };
    }).sort((a, b) => a.x - b.x));
  };

  const removePoint = (id: string) => {
      // Prevent removing start/end for simplicity, or handle logic
      if (points.length <= 2) return; 
      setPoints(prev => prev.filter(p => p.id !== id));
  };

  const resetCurves = () => setPoints([
      { id: 'start', x: 0, y: 0 },
      { id: 'end', x: 255, y: 255 }
  ]);

  // Generate a live preview for the active image
  // Debounce this in the component or here to prevent lag?
  // We'll rely on a small delay or just perform it since LUT is fast.
  // BUT: applying LUT to a 4K image is slow. We should apply to a small thumbnail for preview.

  // Actually, let's process the batch
  const applyBatch = async () => {
    setIsProcessing(true);

    // Process all files
    for (const file of files) {
        if (file.status === ConversionStatus.COMPLETED) continue; // Skip already done unless reset?

        setFiles(prev => prev.map(f => f.id === file.id ? { ...f, status: ConversionStatus.PROCESSING } : f));

        try {
            const blob = await applyCurvesToImage(file.file, lut);
            setFiles(prev => prev.map(f => 
                f.id === file.id ? { 
                    ...f, 
                    status: ConversionStatus.COMPLETED, 
                    convertedBlob: blob,
                    convertedSize: blob.size 
                } : f
            ));
        } catch (e) {
            console.error(e);
            setFiles(prev => prev.map(f => f.id === file.id ? { ...f, status: ConversionStatus.ERROR } : f));
        }
    }
    setIsProcessing(false);
  };

  const downloadZip = async () => {
      try {
        const zip = getZip();
        const completedFiles = files.filter(f => f.status === ConversionStatus.COMPLETED && f.convertedBlob);
        if (completedFiles.length === 0) return;

        completedFiles.forEach(f => {
          const fileName = f.file.name.replace(/\.(png|jpe?g)$/i, '') + '_curve.jpg';
          if (f.convertedBlob) {
            zip.file(fileName, f.convertedBlob);
          }
        });

        const content = await zip.generateAsync({ type: "blob" });
        const url = URL.createObjectURL(content);
        const a = document.createElement("a");
        a.href = url;
        a.download = `BatchBox_Curves_${new Date().toISOString().slice(0,10)}.zip`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      } catch (error) {
        console.error("ZIP generation failed", error);
        alert("Failed to generate ZIP.");
      }
  };

  return {
      files,
      points,
      isProcessing,
      activePreviewId,
      setActivePreviewId,
      handleFilesAdded,
      handleRemoveFile,
      addPoint,
      updatePoint,
      removePoint,
      resetCurves,
      applyBatch,
      downloadZip,
      lut
  };
};

import React, { useRef, useState, useEffect } from 'react';
import { useImageCurves } from '../../hooks/useImageCurves';
import { Activity, Download, RefreshCw, Trash2, RotateCcw, Image as ImageIcon } from 'lucide-react';
import Dropzone from '../Dropzone';
import { applyCurvesToImage, formatBytes } from '../../utils/imageHelper';
import { CurvePoint } from '../../types';

interface CurvesAdjustmentViewProps {
  controller: ReturnType<typeof useImageCurves>;
}

const CurvesAdjustmentView: React.FC<CurvesAdjustmentViewProps> = ({ controller }) => {
  const {
    files,
    points,
    isProcessing,
    activePreviewId,
    setActivePreviewId,
    handleFilesAdded,
    handleRemoveFile,
    addPoint,
    updatePoint,
    removePoint,
    resetCurves,
    applyBatch,
    downloadZip,
    lut
  } = controller;

  const graphRef = useRef<HTMLDivElement>(null);
  const [draggingPointId, setDraggingPointId] = useState<string | null>(null);
  const [previewBlobUrl, setPreviewBlobUrl] = useState<string | null>(null);

  // Generate low-res preview when active image or LUT changes
  useEffect(() => {
    const activeFile = files.find(f => f.id === activePreviewId);
    if (!activeFile) {
        setPreviewBlobUrl(null);
        return;
    }

    // Debounce the preview generation lightly to avoid freezing UI while dragging
    const timer = setTimeout(async () => {
        try {
            // Optimization: Create a smaller version of the image for previewing to keep UI 60fps
            // For now, we use the applyCurvesToImage but assume the browser handles the canvas draw reasonably well for single images.
            // If performance is bad, we would need to resize the source image to max 800px first.
            const blob = await applyCurvesToImage(activeFile.file, lut);
            const url = URL.createObjectURL(blob);
            setPreviewBlobUrl(prev => {
                if (prev) URL.revokeObjectURL(prev);
                return url;
            });
        } catch (e) {
            console.error("Preview error", e);
        }
    }, 50);

    return () => clearTimeout(timer);
  }, [activePreviewId, lut, files.length]); // Intentionally not depending on 'files' deep change, just length to reset

  const handleGraphClick = (e: React.MouseEvent) => {
    if (draggingPointId) return;
    if (!graphRef.current) return;

    const rect = graphRef.current.getBoundingClientRect();
    const x = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
    const y = Math.max(0, Math.min(255, Math.round((1 - (e.clientY - rect.top) / rect.height) * 255)));

    addPoint(x, y);
  };

  const handleMouseMove = (e: MouseEvent) => {
    if (!draggingPointId || !graphRef.current) return;
    e.preventDefault();
    const rect = graphRef.current.getBoundingClientRect();
    const x = Math.max(0, Math.min(255, Math.round(((e.clientX - rect.left) / rect.width) * 255)));
    const y = Math.max(0, Math.min(255, Math.round((1 - (e.clientY - rect.top) / rect.height) * 255)));

    updatePoint(draggingPointId, x, y);
  };

  const handleMouseUp = () => {
    setDraggingPointId(null);
  };

  useEffect(() => {
    if (draggingPointId) {
        window.addEventListener('mousemove', handleMouseMove);
        window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [draggingPointId]);

  // SVG Path Generation for the curve
  const generateSvgPath = () => {
     // Using the pre-calculated LUT to draw the curve smoothly
     // Map LUT index (x) to value (y)
     let d = `M 0 ${255 - lut[0]}`;
     // Reduce resolution for SVG path to keep it light (e.g., every 4 points)
     for(let i=1; i<256; i+=2) {
         d += ` L ${(i/255)*100}% ${100 - (lut[i]/255)*100}%`;
     }
     // Ensure end
     d += ` L 100% ${100 - (lut[255]/255)*100}%`;
     return d;
  };

  const completedCount = files.filter(f => f.status === 'COMPLETED').length;

  return (
    <main className="grid grid-cols-1 lg:grid-cols-12 gap-8 flex-1 relative z-10 animate-in fade-in slide-in-from-bottom-2 duration-300">

      {/* Left Column: Image Preview Area */}
      <div className="lg:col-span-8 flex flex-col gap-4 order-2 lg:order-1 h-full min-h-[500px]">
        {files.length === 0 ? (
          <div className="flex-1 flex flex-col h-full">
             <Dropzone onFilesAdded={handleFilesAdded} />
             <div className="flex-1 mt-6 flex flex-col items-center justify-center text-cyber-dim/40 border-2 border-dashed border-cyber-border/30 rounded-xl bg-cyber-black/20 p-8">
               <Activity size={80} strokeWidth={0.5} className="text-cyber-border" />
               <p className="mt-6 font-mono text-sm tracking-[0.3em] uppercase">No Images Loaded</p>
            </div>
          </div>
        ) : (
          <div className="flex-1 bg-cyber-dark/80 border border-cyber-border rounded-xl relative overflow-hidden flex items-center justify-center shadow-inner group">
            <div className="absolute inset-0 bg-[radial-gradient(#334155_1px,transparent_1px)] bg-[size:20px_20px] opacity-20 pointer-events-none"></div>

            {activePreviewId && files.find(f => f.id === activePreviewId) ? (
                <div className="relative max-w-full max-h-full p-4 flex flex-col items-center">
                    <div className="relative shadow-2xl border border-cyber-border/50">
                        <img 
                            src={previewBlobUrl || files.find(f => f.id === activePreviewId)?.previewUrl} 
                            className="max-w-full max-h-[60vh] object-contain block" 
                            alt="Preview" 
                        />
                        {/* Compare Badge */}
                        <div className="absolute top-2 right-2 bg-cyber-black/80 text-cyber-primary text-[10px] font-mono px-2 py-1 rounded border border-cyber-primary/30 backdrop-blur-sm pointer-events-none">
                            PREVIEW MODE
                        </div>
                    </div>
                    <div className="mt-4 text-center">
                        <p className="text-xs text-cyber-dim font-mono mb-1">{files.find(f => f.id === activePreviewId)?.file.name}</p>
                        <p className="text-[10px] text-cyber-dim/60 font-mono">
                            {files.find(f => f.id === activePreviewId)?.width}x{files.find(f => f.id === activePreviewId)?.height}
                        </p>
                    </div>
                </div>
            ) : (
                <div className="text-cyber-dim font-mono text-sm">Select an image to preview</div>
            )}

            {/* File Strip */}
            <div className="absolute bottom-0 left-0 right-0 h-24 bg-cyber-black/90 border-t border-cyber-border/50 p-2 flex gap-2 overflow-x-auto custom-scrollbar backdrop-blur-md">
                {files.map(file => (
                    <div 
                        key={file.id} 
                        onClick={() => setActivePreviewId(file.id)}
                        className={`
                            relative w-20 h-full flex-shrink-0 cursor-pointer border rounded overflow-hidden transition-all group/item
                            ${activePreviewId === file.id ? 'border-cyber-primary ring-1 ring-cyber-primary shadow-[0_0_10px_rgba(6,182,212,0.3)]' : 'border-cyber-border opacity-60 hover:opacity-100'}
                        `}
                    >
                        <img src={file.previewUrl} className="w-full h-full object-cover" alt="" />
                        {file.status === 'COMPLETED' && <div className="absolute inset-0 bg-emerald-500/20 flex items-center justify-center"><div className="w-2 h-2 rounded-full bg-emerald-400 shadow-neon"></div></div>}
                        <button 
                            onClick={(e) => { e.stopPropagation(); handleRemoveFile(file.id); }}
                            className="absolute top-1 right-1 bg-black/50 text-white p-0.5 rounded opacity-0 group-hover/item:opacity-100 hover:bg-red-500 hover:text-white transition-all"
                        >
                            <Trash2 size={10} />
                        </button>
                    </div>
                ))}
                <div className="w-20 h-full flex-shrink-0 border border-dashed border-cyber-border rounded flex items-center justify-center hover:bg-cyber-panel/30 transition-colors">
                     <Dropzone onFilesAdded={handleFilesAdded} compact={true} />
                </div>
            </div>
          </div>
        )}
      </div>

      {/* Right Column: Curve Editor */}
      <div className="lg:col-span-4 space-y-6 order-1 lg:order-2 flex flex-col h-fit sticky top-8">
        <div className="bg-cyber-panel/40 backdrop-blur-md border border-cyber-border p-6 shadow-2xl rounded-lg">
            <div className="flex items-center justify-between mb-6">
                <h2 className="text-lg font-bold text-cyber-text flex items-center gap-3 font-mono uppercase tracking-wide">
                    <Activity size={18} className="text-cyber-primary" />
                    Curve Map
                </h2>
                <button 
                    onClick={resetCurves}
                    className="text-[10px] flex items-center gap-1 text-cyber-dim hover:text-cyber-primary transition-colors uppercase tracking-wider"
                >
                    <RotateCcw size={12} /> Reset
                </button>
            </div>

            {/* The Graph */}
            <div className="aspect-square relative bg-cyber-black border border-cyber-border rounded-lg shadow-inner select-none cursor-crosshair group overflow-hidden" ref={graphRef} onClick={handleGraphClick}>
                {/* Grid Lines */}
                <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none opacity-20">
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-b border-cyber-dim/50"></div>
                    <div className="border-r border-cyber-dim/50"></div>
                    <div className="border-r border-cyber-dim/50"></div>
                    <div className="border-r border-cyber-dim/50"></div>
                    <div></div>
                </div>

                {/* Diagonal Helper */}
                <div className="absolute inset-0 border-t border-l border-transparent">
                     <svg className="w-full h-full pointer-events-none opacity-10" viewBox="0 0 100 100" preserveAspectRatio="none">
                         <line x1="0" y1="100" x2="100" y2="0" stroke="currentColor" strokeWidth="0.5" className="text-cyber-dim" />
                     </svg>
                </div>

                {/* The Curve SVG */}
                <svg className="absolute inset-0 w-full h-full pointer-events-none z-10 overflow-visible">
                    <path 
                        d={generateSvgPath()} 
                        fill="none" 
                        stroke="#06b6d4" 
                        strokeWidth="2" 
                        vectorEffect="non-scaling-stroke"
                        className="drop-shadow-[0_0_5px_rgba(6,182,212,0.5)]"
                    />
                    <path 
                        d={`${generateSvgPath()} L 100% 100% L 0 100% Z`} 
                        fill="url(#curveGradient)" 
                        opacity="0.2"
                    />
                    <defs>
                        <linearGradient id="curveGradient" x1="0" x2="0" y1="0" y2="1">
                            <stop offset="0%" stopColor="#06b6d4" />
                            <stop offset="100%" stopColor="transparent" />
                        </linearGradient>
                    </defs>
                </svg>

                {/* Control Points */}
                {points.map((p, index) => (
                    <div
                        key={p.id}
                        className={`absolute w-3 h-3 -ml-1.5 -mt-1.5 rounded-full border-2 cursor-grab active:cursor-grabbing transition-transform hover:scale-125 z-20 ${
                            draggingPointId === p.id ? 'bg-cyber-text border-cyber-primary shadow-[0_0_10px_rgba(255,255,255,0.5)] scale-125' : 'bg-cyber-black border-cyber-primary'
                        }`}
                        style={{
                            left: `${(p.x / 255) * 100}%`,
                            top: `${100 - (p.y / 255) * 100}%`
                        }}
                        onMouseDown={(e) => {
                            e.stopPropagation();
                            setDraggingPointId(p.id);
                        }}
                        onDoubleClick={(e) => {
                            e.stopPropagation();
                            if (index !== 0 && index !== points.length - 1) {
                                removePoint(p.id);
                            }
                        }}
                    ></div>
                ))}
            </div>

            <div className="mt-4 text-center">
                <p className="text-[10px] text-cyber-dim uppercase tracking-widest font-mono">
                    Double-click point to delete • Drag to adjust
                </p>
            </div>
        </div>

        {/* Action Panel */}
        <div className="bg-cyber-panel/20 border border-cyber-border p-4 rounded-lg space-y-3">
             <div className="flex justify-between text-xs font-mono text-cyber-dim uppercase">
                 <span>Batch Ready</span>
                 <span className={files.length > 0 ? 'text-cyber-text' : ''}>{files.length} Images</span>
             </div>

             <button
                onClick={applyBatch}
                disabled={isProcessing || files.length === 0}
                className="w-full py-3 bg-cyber-primary/10 border border-cyber-primary text-cyber-primary font-bold text-xs uppercase tracking-widest hover:bg-cyber-primary/20 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
             >
                {isProcessing ? <RefreshCw size={16} className="animate-spin" /> : <RefreshCw size={16} />}
                APPLY CURVES
             </button>

             {completedCount > 0 && !isProcessing && (
                <button
                    onClick={downloadZip}
                    className="w-full py-3 bg-cyber-accent/10 border border-cyber-accent text-cyber-accent font-bold text-xs uppercase tracking-widest hover:bg-cyber-accent/20 transition-all flex items-center justify-center gap-2"
                >
                    <Download size={16} />
                    DOWNLOAD ZIP ({completedCount})
                </button>
             )}
        </div>
      </div>

    </main>
  );
};

