                    >
                        <img src={file.previewUrl} className="w-full h-full object-cover" alt="" />
                        {file.status === 'COMPLETED' && <div className="absolute inset-0 bg-emerald-500/20 flex items-center justify-center"><div className="w-2 h-2 rounded-full bg-emerald-400 shadow-neon"></div></div>}
                        <button 
                            onClick={(e) => { e.stopPropagation(); handleRemoveFile(file.id); }}
                            className="absolute top-1 right-1 bg-black/70 text-white p-1 rounded-sm opacity-0 group-hover/item:opacity-100 hover:bg-red-500 hover:text-white transition-all backdrop-blur-sm"
                        >
                            <Trash2 size={10} />
                        </button>
                    </div>
                ))}

                {/* Compact Dropzone in strip */}
                <div className="w-20 h-full flex-shrink-0">
                     <Dropzone onFilesAdded={handleFilesAdded} compact={true} />
                </div>
            </div>
          </div>
        )}
      </div>

      {/* Right Column: Curve Editor */}
      <div className="lg:col-span-4 space-y-6 order-1 lg:order-2 flex flex-col h-fit sticky top-8">
        <div className="bg-cyber-panel/40 backdrop-blur-md border border-cyber-border p-6 shadow-2xl rounded-lg relative overflow-hidden">
            {/* Decoration */}
            <div className="absolute top-0 right-0 w-20 h-20 bg-cyber-primary/5 rounded-full blur-2xl -mr-10 -mt-10 pointer-events-none"></div>

            <div className="flex items-center justify-between mb-6 relative z-10">
                <h2 className="text-lg font-bold text-cyber-text flex items-center gap-3 font-mono uppercase tracking-wide">
                    <Activity size={18} className="text-cyber-primary" />
                    Curve Map
                </h2>
                <button 
                    onClick={resetCurves}
                    className="text-[10px] flex items-center gap-1 text-cyber-dim hover:text-cyber-primary transition-colors uppercase tracking-wider bg-cyber-black/50 px-2 py-1 rounded border border-cyber-border/50"
                >
                    <RotateCcw size={10} /> Reset
                </button>
            </div>

            {/* The Graph */}
            <div className="aspect-square relative bg-cyber-black border border-cyber-border rounded-lg shadow-inner select-none cursor-crosshair group overflow-hidden" ref={graphRef} onClick={handleGraphClick}>
                {/* Grid Lines */}
                <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 pointer-events-none opacity-20">
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-r border-b border-cyber-dim/50"></div>
                    <div className="border-b border-cyber-dim/50"></div>
                    <div className="border-r border-cyber-dim/50"></div>
                    <div className="border-r border-cyber-dim/50"></div>
                    <div className="border-r border-cyber-dim/50"></div>
                    <div></div>
                </div>

                {/* Diagonal Helper */}
                <div className="absolute inset-0 border-t border-l border-transparent">
                     <svg className="w-full h-full pointer-events-none opacity-10" viewBox="0 0 100 100" preserveAspectRatio="none">
                         <line x1="0" y1="100" x2="100" y2="0" stroke="currentColor" strokeWidth="0.5" className="text-cyber-dim" />
                     </svg>
                </div>

                {/* The Curve SVG */}
                <svg className="absolute inset-0 w-full h-full pointer-events-none z-10 overflow-visible">
                    {/* Shadow/Glow Effect */}
                    <path 
                        d={generateSvgPath()} 
                        fill="none" 
                        stroke="#06b6d4" 
                        strokeWidth="4" 
                        strokeOpacity="0.2"
                        vectorEffect="non-scaling-stroke"
                        className="blur-sm"
                    />
                    {/* Main Line */}
                    <path 
                        d={generateSvgPath()} 
                        fill="none" 
                        stroke="#06b6d4" 
                        strokeWidth="2" 
                        vectorEffect="non-scaling-stroke"
                        className="drop-shadow-[0_0_2px_rgba(255,255,255,0.5)]"
                    />
                    {/* Fill Area */}
                    <path 
                        d={`${generateSvgPath()} L 100% 100% L 0 100% Z`} 
                        fill="url(#curveGradient)" 
                        opacity="0.15"
                    />
                    <defs>
                        <linearGradient id="curveGradient" x1="0" x2="0" y1="0" y2="1">
                            <stop offset="0%" stopColor="#06b6d4" />
                            <stop offset="100%" stopColor="transparent" />
                        </linearGradient>
                    </defs>
                </svg>

                {/* Control Points */}
                {points.map((p, index) => (
                    <div
                        key={p.id}
                        className={`absolute w-3 h-3 -ml-1.5 -mt-1.5 rounded-full border-2 cursor-grab active:cursor-grabbing transition-transform z-20 ${
                            draggingPointId === p.id 
                            ? 'bg-cyber-text border-cyber-primary shadow-[0_0_15px_rgba(6,182,212,0.8)] scale-150' 
                            : 'bg-cyber-black border-cyber-primary hover:scale-125'
                        }`}
                        style={{
                            left: `${(p.x / 255) * 100}%`,
                            top: `${100 - (p.y / 255) * 100}%`
                        }}
                        onMouseDown={(e) => {
                            e.stopPropagation();
                            setDraggingPointId(p.id);
                        }}
                        onDoubleClick={(e) => {
                            e.stopPropagation();
                            if (index !== 0 && index !== points.length - 1) {
                                removePoint(p.id);
                            }
                        }}
                    ></div>
                ))}
            </div>

            <div className="mt-4 text-center">
                <p className="text-[10px] text-cyber-dim uppercase tracking-widest font-mono">
                    Double-click point to delete • Drag to adjust
                </p>
            </div>
        </div>

        {/* Action Panel */}
        <div className="bg-cyber-panel/20 border border-cyber-border p-4 rounded-lg space-y-3">
             <div className="flex justify-between text-xs font-mono text-cyber-dim uppercase">
                 <span>Batch Ready</span>
                 <span className={files.length > 0 ? 'text-cyber-text' : ''}>{files.length} Images</span>
             </div>

             <button
                onClick={applyBatch}
                disabled={isProcessing || files.length === 0}
                className="w-full py-3 bg-cyber-primary/10 border border-cyber-primary text-cyber-primary font-bold text-xs uppercase tracking-widest hover:bg-cyber-primary/20 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
             >
                {isProcessing ? <RefreshCw size={16} className="animate-spin" /> : <RefreshCw size={16} />}
                APPLY CURVES
             </button>

             {completedCount > 0 && !isProcessing && (
                <button
                    onClick={downloadZip}
                    className="w-full py-3 bg-cyber-accent/10 border border-cyber-accent text-cyber-accent font-bold text-xs uppercase tracking-widest hover:bg-cyber-accent/20 transition-all flex items-center justify-center gap-2"
                >
                    <Download size={16} />
                    DOWNLOAD ZIP ({completedCount})
                </button>
             )}
        </div>
      </div>

    </main>
  );
};

export default CurvesAdjustmentView;
